# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        val sharedIntent = intent
        if (sharedIntent.action == Intent.ACTION_SEND) {
            handleSendIntent(sharedIntent)
        }
    }

    private fun handleSendIntent(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                processSharedText(sharedText)
            }
            "image/*" -> {
                val sharedImageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                processSharedImage(sharedImageUri)
            }
        }
    }

    private fun processSharedText(text: String?) {
        val textView: TextView = findViewById(R.id.shared_text_view)
        textView.text = "Shared Text: $text"
    }

    private fun processSharedImage(imageUri: Uri?) {
        val imageView: ImageView = findViewById(R.id.shared_image_view)
        Glide.with(this).load(imageUri).into(imageView)
    }
}